/* eslint-disable */
import "./LogoSearch.css";
import React, { useEffect, useState } from "react";
import { BiSearch } from "react-icons/bi";
import { useSelector } from "react-redux";
import SearchCard from "../SearchCard/SearchCard";

function LogoSearch({ searchNow }) {
  const { user } = useSelector((state) => state.AuthReducer.authData);
  let { users } = useSelector((state) => state.UserReducer);
  if (users && users.length > 0)
    users = users.filter((u) => u._id !== user?._id);
  const [serachText, setSearchText] = useState("");
  const [results, setResults] = useState([]);

  useEffect(() => {
    if (users) {
      const searched = users.filter((user) =>
        user.username.includes(serachText)
      );
      if (serachText)
        setResults(() =>
          searched.sort((a, b) => {
            return a.username[0] !== serachText ? 1 : -1;
          })
        );
      else setResults([]);
    }
  }, [serachText]);

  const handleSearch = (e) => {
    setSearchText(() => e.target.value.trim());
  };

  return (
    <div className="search-container">
      <div className="search-bar">
        <BiSearch
          size="26px"
          color="var(--main)"
          style={{ cursor: "pointer" }}
        />
        <input
          type="text"
          placeholder={searchNow || "بحث"}
          onChange={handleSearch}
          style={{ direction: `${searchNow ? "ltr" : "rtl"}` }}
        />
      </div>
      {results.length > 0 && (
        <div className="search-list">
          {results.map((user) => (
            <SearchCard user={user} key={user._id} setSearchText />
          ))}
        </div>
      )}
    </div>
  );
}

export default LogoSearch;
